#include <stdio.h>
#include <stdlib.h>

#define MAX 200005

typedef struct Node {
    int vertex;
    struct Node* next;
} Node;

Node* adj[MAX]; // Adjacency list
int indegree[MAX]; // Array to store the indegree of nodes
int queue[MAX]; // Queue for BFS
int front = 0, rear = 0; // Queue pointers
int courseOrder[MAX]; // Array to store topological order

// Function to create a new node in adjacency list
Node* createNode(int v) {
    Node* newNode = (Node*)malloc(sizeof(Node));
    newNode->vertex = v;
    newNode->next = NULL;
    return newNode;
}

void enqueue(int node) {
    queue[rear++] = node;
}

int dequeue() {
    return queue[front++];
}

int isEmpty() {
    return front == rear;
}

void findOrder(int n) {
    int i, node;

    // Enqueue all nodes with indegree 0
    for (i = 1; i <= n; i++) {
        if (indegree[i] == 0) {
            enqueue(i);
        }
    }

    int courseIndex = 0;

    // Perform BFS
    while (!isEmpty()) {
        node = dequeue(); // Get the node from the front of the queue
        courseOrder[courseIndex++] = node;

        // Visit all neighbors of the dequeued node
        Node* temp = adj[node];
        while (temp != NULL) {
            int v = temp->vertex;
            indegree[v]--;
            if (indegree[v] == 0) {
                enqueue(v);
            }
            temp = temp->next;
        }
    }

    // Check if topological sort is possible
    if (courseIndex == n) {
        for (i = 0; i < courseIndex; i++) {
            printf("%d ", courseOrder[i]);
        }
        printf("\n");
    } else {
        printf("-1\n"); // Cycle detected or incomplete order
    }
}

int main() {
    int t;
    scanf("%d", &t);
    while(t--){
        int n, m, a, b;
        scanf("%d %d", &n, &m);

        // Initialize adjacency list and indegree array
        for (int i = 1; i <= n; i++) {
            adj[i] = NULL;
            indegree[i] = 0;
        }

        // Read the edges
        for (int i = 0; i < m; i++) {
            scanf("%d %d", &a, &b);

            // Add edge a -> b in the adjacency list
            Node* newNode = createNode(b);
            newNode->next = adj[a];
            adj[a] = newNode;

            // Increment indegree of node b
            indegree[b]++;
        }

        // Perform topological sort
        findOrder(n);
    }
    return 0;
}

