        // Decrease the indegree of all adjacent nodes
        for (let v of adj[node]) {
            indegree[v]--;
            if (indegree[v] === 0) {
                q.push(v);
            }
        }
    }

    if (courseOrder.length === n) {
        console.log(courseOrder.join(' '));
